do $$ begin if exists (select 1 from information_schema.columns where table_schema='public' and table_name='perfis' and column_name='user_id') then alter table public.perfis rename column user_id to id; end if; end $$;
create schema if not exists private;
alter table public.perfis add column if not exists id_colaborador integer;
create table if not exists public.status_contrato (codigo text primary key, descricao text not null, ordem integer not null default 0, ativo boolean not null default true);
create table if not exists public.status_unidade (codigo text primary key, descricao text not null, ordem integer not null default 0, ativo boolean not null default true);
create table if not exists public.status_ordem (codigo text primary key, descricao text not null, ordem integer not null default 0, ativo boolean not null default true);
create table if not exists public.status_atendimento (codigo text primary key, descricao text not null, ordem integer not null default 0, ativo boolean not null default true);
create table if not exists public.status_pendencia (codigo text primary key, descricao text not null, ordem integer not null default 0, ativo boolean not null default true);
create table if not exists public.tipos_movimentacao (codigo text primary key, descricao text not null, fator integer not null check (fator in (-1,1)), ativo boolean not null default true);
insert into public.status_contrato(codigo,descricao,ordem) values ('ativo','Ativo',10),('suspenso','Suspenso',20),('encerrado','Encerrado',30),('cancelado','Cancelado',40) on conflict(codigo) do update set descricao=excluded.descricao, ordem=excluded.ordem;
insert into public.status_unidade(codigo,descricao,ordem) values ('instalada','Instalada',10),('em_manutencao','Em manutencao',20),('desmobilizada','Desmobilizada',30),('inativa','Inativa',40) on conflict(codigo) do update set descricao=excluded.descricao, ordem=excluded.ordem;
insert into public.status_ordem(codigo,descricao,ordem) values ('aberta','Aberta',10),('em_andamento','Em andamento',20),('concluida','Concluida',30),('cancelada','Cancelada',40) on conflict(codigo) do update set descricao=excluded.descricao, ordem=excluded.ordem;
insert into public.status_atendimento(codigo,descricao,ordem) values ('aberto','Aberto',10),('em_execucao','Em execucao',20),('concluido','Concluido',30),('cancelado','Cancelado',40) on conflict(codigo) do update set descricao=excluded.descricao, ordem=excluded.ordem;
insert into public.status_pendencia(codigo,descricao,ordem) values ('aberta','Aberta',10),('em_tratamento','Em tratamento',20),('concluida','Concluida',30),('cancelada','Cancelada',40) on conflict(codigo) do update set descricao=excluded.descricao, ordem=excluded.ordem;
insert into public.tipos_movimentacao(codigo,descricao,fator) values ('entrada','Entrada',1),('saida','Saida',-1),('ajuste','Ajuste manual',1) on conflict(codigo) do update set descricao=excluded.descricao, fator=excluded.fator;
create table if not exists public.clientes (id_cliente integer generated by default as identity primary key,nome text not null,documento text,email text,telefone text,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.empresas (id_empresa integer generated by default as identity primary key,razao_social text not null,nome_fantasia text,cnpj text not null unique,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.contratos (id_contrato integer generated by default as identity primary key,id_cliente integer not null references public.clientes(id_cliente) on delete restrict,id_empresa integer not null references public.empresas(id_empresa) on delete restrict,numero_contrato text not null unique,objeto text not null default '',status_codigo text not null references public.status_contrato(codigo) on delete restrict default 'ativo',data_inicio date,data_fim date,valor_total numeric(12,2),ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.projetos (id_projeto integer generated by default as identity primary key,id_contrato integer not null references public.contratos(id_contrato) on delete restrict,nome text not null,municipio text not null default '',uf text not null default '',ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.unidades_instaladas (id_unidade integer generated by default as identity primary key,id_projeto integer not null references public.projetos(id_projeto) on delete restrict,codigo text not null unique,nome text not null,status_codigo text not null references public.status_unidade(codigo) on delete restrict default 'instalada',ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.colaboradores (id_colaborador integer generated by default as identity primary key,nome text not null,cargo text,email text,telefone text,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.terceirizados (id_terceira integer generated by default as identity primary key,nome text not null,empresa text,documento text,telefone text,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
alter table public.perfis drop constraint if exists perfis_id_colaborador_fkey, add constraint perfis_id_colaborador_fkey foreign key (id_colaborador) references public.colaboradores(id_colaborador) on delete restrict;
create table if not exists public.estoque_materiais (id_material integer generated by default as identity primary key,codigo text unique,descricao text not null,categoria text not null default '',unidade_medida text not null default 'un',estoque_minimo numeric(12,2) not null default 0,estoque_atual numeric(12,2) not null default 0,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.pendencias_padrao (id_pendencia integer generated by default as identity primary key,codigo text unique,descricao text not null,ativo boolean not null default true,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.ordens_manutencao (id_ordem integer generated by default as identity primary key,id_unidade integer not null references public.unidades_instaladas(id_unidade) on delete restrict,protocolo text not null unique,tipo text not null default 'corretiva',prioridade text not null default 'P3' check (prioridade in ('P1','P2','P3','P4')),status_codigo text not null references public.status_ordem(codigo) on delete restrict default 'aberta',abertura_em timestamptz not null default now(),prazo_sla timestamptz,data_conclusao timestamptz,descricao text not null default '',criado_por uuid references public.perfis(id) on delete restrict,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.pendencias_ordem_manutencao (id_pendencia_ordem integer generated by default as identity primary key,id_ordem integer not null references public.ordens_manutencao(id_ordem) on delete restrict,id_pendencia integer not null references public.pendencias_padrao(id_pendencia) on delete restrict,status_codigo text not null references public.status_pendencia(codigo) on delete restrict default 'aberta',descricao_snapshot text not null,criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now(),unique(id_ordem,id_pendencia));
create table if not exists public.atendimentos_ordens (id_atendimento integer generated by default as identity primary key,id_ordem integer not null references public.ordens_manutencao(id_ordem) on delete restrict,status_codigo text not null references public.status_atendimento(codigo) on delete restrict default 'aberto',data_abertura timestamptz not null default now(),data_fechamento timestamptz,relato text not null default '',criado_por uuid not null references public.perfis(id) on delete restrict default auth.uid(),criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.equipes (id_equipe integer generated by default as identity primary key,id_atendimento integer not null references public.atendimentos_ordens(id_atendimento) on delete restrict,id_colaborador integer references public.colaboradores(id_colaborador) on delete restrict,id_terceira integer references public.terceirizados(id_terceira) on delete restrict,funcao text,criado_por uuid not null references public.perfis(id) on delete restrict default auth.uid(),criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now(),constraint equipes_um_membro_check check ((id_colaborador is not null and id_terceira is null) or (id_colaborador is null and id_terceira is not null)));
create table if not exists public.atendimentos_executados (id_execucao integer generated by default as identity primary key,id_atendimento integer not null references public.atendimentos_ordens(id_atendimento) on delete restrict,id_pendencia_ordem integer not null references public.pendencias_ordem_manutencao(id_pendencia_ordem) on delete restrict,status_codigo text not null references public.status_pendencia(codigo) on delete restrict default 'aberta',observacao text not null default '',criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now(),unique(id_atendimento,id_pendencia_ordem));
create table if not exists public.movimentacoes (id_movimentacao integer generated by default as identity primary key,data_movimentacao timestamptz not null default now(),tipo_codigo text not null references public.tipos_movimentacao(codigo) on delete restrict,origem text not null default '',observacao text not null default '',criado_por uuid not null references public.perfis(id) on delete restrict default auth.uid(),criado_em timestamptz not null default now(),atualizado_em timestamptz not null default now());
create table if not exists public.movimentacoes_estoque (id_movimentacao_estoque integer generated by default as identity primary key,id_movimentacao integer not null references public.movimentacoes(id_movimentacao) on delete restrict,id_material integer not null references public.estoque_materiais(id_material) on delete restrict,id_atendimento integer references public.atendimentos_ordens(id_atendimento) on delete restrict,quantidade numeric(12,2) not null check (quantidade <> 0),criado_em timestamptz not null default now());
create table if not exists public.historico_unidade (id_historico integer generated by default as identity primary key,id_unidade integer not null references public.unidades_instaladas(id_unidade) on delete restrict,descricao text not null,registrado_em timestamptz not null default now());
create table if not exists public.notificacoes (id_notificacao integer generated by default as identity primary key,id_ordem integer references public.ordens_manutencao(id_ordem) on delete restrict,data_recebimento timestamptz not null default now(),assunto text not null default '',conteudo text not null default '');;
